module RefModule(
    input clk,reset,
    output [3:0] dout
    );reg [3:0]final_sig;
    integer i;

    always@(posedge clk) begin
        if(reset)
            final_sig<=4'b0000;
        else begin
            final_sig[3]<=~final_sig[0];
            for(i=0;i<3;i=i+1) begin
                final_sig[i]<=final_sig[i+1];
             end
         end
    end

    assign dout=final_sig;

endmodule
